	private boolean supportsSampling(Filter filter, StatementPattern pattern) {
		if (filter == null || filter.getCondition() == null || pattern == null) {
			return false;
		}
		Set<String> patternBindings = pattern.getBindingNames();
		if (patternBindings.isEmpty()) {
			return false;
		}

		final boolean[] supported = { true };
		filter.getCondition().visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Var node) {
				if (!supported[0]) {
					return;
				}
				if (!node.hasValue() && node.getName() != null && !patternBindings.contains(node.getName())) {
					supported[0] = false;
				}
			}

			@Override
			public void meet(Exists node) {
				supported[0] = false;
			}

			@Override
			public void meet(CompareAny node) {
				supported[0] = false;
			}

			@Override
			public void meet(CompareAll node) {
				supported[0] = false;
			}
		});
		return supported[0];
	}

	private PatternFilterKey samplingKey(Filter filter, StatementPattern pattern) {
		if (filter == null || filter.getCondition() == null || pattern == null) {
			return null;
		}
		PatternKey patternKey = FilterSelectivityKeys.patternKeyFor(pattern);
		if (patternKey == null) {
			return null;
		}
		return new PatternFilterKey(patternKey, FilterSelectivityKeys.filterKeyFor(filter.getCondition()));
	}

	private long resolvePatternId(Var var) throws IOException {
		if (var == null || !var.hasValue()) {
			return LmdbValue.UNKNOWN_ID;
		}
		long id = valueStore.getId(var.getValue());
		return id == LmdbValue.UNKNOWN_ID ? MISSING_VALUE_ID : id;
	}

	private boolean matchesRepeatedVarEquality(StatementPattern pattern, long[] row) {
		Map<String, Long> bindingsByName = new HashMap<>(4);
		return matchesRepeatedVar(pattern.getSubjectVar(), row[TripleStore.SUBJ_IDX], bindingsByName)
				&& matchesRepeatedVar(pattern.getPredicateVar(), row[TripleStore.PRED_IDX], bindingsByName)
				&& matchesRepeatedVar(pattern.getObjectVar(), row[TripleStore.OBJ_IDX], bindingsByName)
				&& matchesRepeatedVar(pattern.getContextVar(), row[TripleStore.CONTEXT_IDX], bindingsByName);
	}

	private boolean matchesRepeatedVar(Var var, long valueId, Map<String, Long> bindingsByName) {
		if (var == null || var.hasValue() || var.getName() == null) {
			return true;
		}
		Long existing = bindingsByName.putIfAbsent(var.getName(), valueId);
		return existing == null || existing.longValue() == valueId;
	}

	private BindingSet toBindingSet(StatementPattern pattern, long[] row) throws IOException {
		QueryBindingSet bindingSet = new QueryBindingSet();
		addBinding(bindingSet, pattern.getSubjectVar(), row[TripleStore.SUBJ_IDX]);
		addBinding(bindingSet, pattern.getPredicateVar(), row[TripleStore.PRED_IDX]);
		addBinding(bindingSet, pattern.getObjectVar(), row[TripleStore.OBJ_IDX]);
		addBinding(bindingSet, pattern.getContextVar(), row[TripleStore.CONTEXT_IDX]);
		return bindingSet;
	}

	private void addBinding(QueryBindingSet bindingSet, Var var, long valueId) throws IOException {
		if (var == null || var.hasValue() || var.getName() == null || bindingSet.hasBinding(var.getName())
				|| valueId == 0L) {
			return;
		}
		bindingSet.addBinding(var.getName(), valueStore.getValue(valueId));
	}

