	private static final class LearnedCounts {
		private long passedCount;
		private long filteredCount;

		private void add(long passedCount, long filteredCount) {
			this.passedCount += Math.max(0L, passedCount);
			this.filteredCount += Math.max(0L, filteredCount);
		}

		private long total() {
			return passedCount + filteredCount;
		}

		private double passRatio() {
			long total = total();
			if (total <= 0L) {
				return -1.0d;
			}
			return (double) passedCount / total;
		}

		private void writeTo(DataOutputStream out) throws IOException {
			out.writeLong(passedCount);
			out.writeLong(filteredCount);
		}

		private static LearnedCounts readFrom(DataInputStream in) throws IOException {
			LearnedCounts counts = new LearnedCounts();
			counts.passedCount = Math.max(0L, in.readLong());
			counts.filteredCount = Math.max(0L, in.readLong());
			return counts;
		}
	}

